"use client";

import AshokaEmblem from "@/components/shared/AshokaEmblem";
import { ChevronDown, MessageSquare, Palette, Search, Share2, CalendarDays } from "lucide-react";
import { useEffect, useState } from "react";

const heroImages = ["/images/hero/Hero3.jpg", "/images/hero/Hero2.webp", "/images/hero/Hero1.webp"];
const categories = ["All Categories", "Acts", "Citizen Engagements", "Directory", "Explore India", "News", "Schemes", "Services"];
const trendingSearches = ["Apply Aadhaar", "DigiLocker", "New Voter Registration", "Tatkaal Passport Service", "Apply for Driving Licence"];

export default function Hero() {
  const [currentSlide, setCurrentSlide] = useState(0);

  useEffect(() => {
    const timer = window.setInterval(() => setCurrentSlide((value) => (value + 1) % heroImages.length), 7000);
    return () => window.clearInterval(timer);
  }, []);

  return (
    <section id="main-content" className="relative isolate min-h-[calc(100vh-10px)] overflow-hidden">
      {heroImages.map((src, index) => (
        <div
          key={src}
          className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000"
          style={{ backgroundImage: `url(${src})`, opacity: index === currentSlide ? 1 : 0 }}
          aria-hidden="true"
        />
      ))}
      <div className="absolute inset-0 bg-[linear-gradient(90deg,rgba(2,27,82,.9),rgba(41,31,96,.72)_48%,rgba(15,61,124,.72)),linear-gradient(180deg,rgba(2,8,28,.24),rgba(31,19,70,.72))]" />

      <div className="relative mx-auto flex min-h-[calc(100vh-10px)] max-w-[1440px] flex-col items-center justify-center px-4 pb-36 pt-28 text-center sm:px-6 lg:pt-32">
        <div className="mx-auto flex max-w-[1160px] flex-col items-center">
          <AshokaEmblem className="h-[96px] w-[96px] drop-shadow-[0_12px_30px_rgba(0,0,0,.28)] sm:h-[126px] sm:w-[126px]" color="white" />
          <div className="mt-3">
            <div className="flex flex-wrap items-end justify-center gap-3">
              <h1 className="text-[3.05rem] font-black leading-none tracking-normal text-white drop-shadow-[0_14px_34px_rgba(0,0,0,.3)] sm:text-[5.7rem] lg:text-[6.4rem]">
                india.gov.in
              </h1>
              <span className="mb-2 rounded-sm bg-[#ffd829] px-2.5 py-1 text-xl font-black text-black sm:mb-4 sm:text-2xl">
                BETA
              </span>
            </div>
            <div className="mx-auto mt-1 grid max-w-[580px] grid-cols-[1fr_1fr] gap-14 px-3" aria-hidden="true">
              <span className="h-2 bg-[#ff9933]" />
              <span className="h-2 bg-[#138808]" />
            </div>
          </div>
          <p className="mt-3 text-2xl font-bold tracking-wide text-white sm:text-[2rem]">National Portal of India</p>
          <p className="mt-6 text-xl font-medium text-white sm:text-[1.7rem]">Where Government Information Converges</p>

          <div className="mx-auto mt-8 flex w-full max-w-[1210px] flex-col overflow-hidden rounded-lg bg-white/95 shadow-[0_18px_60px_rgba(0,0,0,.28)] ring-1 ring-white/30 sm:flex-row">
            <div className="flex min-w-0 flex-1 items-center gap-5 px-6">
              <Search size={31} className="shrink-0 text-slate-500" />
              <label htmlFor="hero-search" className="sr-only">Search India Portal</label>
              <input id="hero-search" type="search" placeholder="Search for" className="h-[88px] w-full bg-transparent text-xl text-slate-800 outline-none placeholder:text-slate-400 sm:text-2xl" />
            </div>
            <div className="relative border-t border-slate-300 bg-white sm:border-l sm:border-t-0">
              <label htmlFor="hero-category" className="sr-only">Search category</label>
              <select id="hero-category" defaultValue="All Categories" className="h-[88px] w-full appearance-none bg-white pl-6 pr-14 text-xl text-slate-600 outline-none sm:w-[250px] sm:text-2xl">
                {categories.map((category) => <option key={category}>{category}</option>)}
              </select>
              <ChevronDown size={21} className="pointer-events-none absolute right-6 top-1/2 -translate-y-1/2 text-slate-700" />
            </div>
            <button type="button" className="h-[88px] bg-[#ed1b2f] px-14 text-2xl font-bold text-white transition hover:bg-[#cf1626] sm:text-[1.65rem]">
              Search
            </button>
          </div>

          <div className="mt-10 flex flex-wrap items-center justify-center gap-2.5">
            <span className="mr-1 text-xl font-bold text-white">Trending Searches :</span>
            {trendingSearches.map((term) => (
              <button key={term} type="button" className="rounded border border-white/35 bg-white/5 px-4 py-2.5 text-lg font-medium text-white backdrop-blur-sm transition hover:border-white/65 hover:bg-white/12">
                {term}
              </button>
            ))}
          </div>
        </div>

        <div className="absolute bottom-28 right-5 hidden flex-col overflow-hidden rounded-lg bg-[#071d49]/65 shadow-[0_18px_50px_rgba(0,0,0,.2)] backdrop-blur-sm lg:flex">
          {[MessageSquare, CalendarDays, Share2, Palette].map((Icon, index) => (
            <button key={index} type="button" aria-label={`Quick tool ${index + 1}`} className="flex h-14 w-14 items-center justify-center border-b border-white/10 p-4 text-white transition hover:bg-white/14">
              <Icon size={22} strokeWidth={1.9} />
            </button>
          ))}
        </div>
      </div>
    </section>
  );
}
